const jobs = $input.first().json.data || [];
const config = $('⚙️ CONFIG — Edit Your Details Here').first().json;
const limit = parseInt(config.DAILY_APPLY_LIMIT) || 5;

// Deduplicate and take top N
const seen = new Set();
const unique = jobs.filter(j => {
  const key = (j.employer_name + j.job_title).toLowerCase().replace(/[^a-z0-9]/g,'');
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

return unique.slice(0, limit * 3).map(j => ({
  json: {
    job_id:          j.job_id || '',
    job_title:       j.job_title || '',
    company:         j.employer_name || '',
    location:        j.job_city ? `${j.job_city}, ${j.job_country || ''}` : (j.job_country || 'Remote'),
    is_remote:       j.job_is_remote || false,
    apply_link:      j.job_apply_link || j.job_google_link || '',
    description:     (j.job_description || '').substring(0, 2000),
    required_skills: (j.job_required_skills || []).join(', '),
    min_salary:      j.job_min_salary || '',
    max_salary:      j.job_max_salary || '',
    posted_date:     j.job_posted_at_datetime_utc || new Date().toISOString(),
    employer_website:j.employer_website || '',
    source:          j.job_publisher || 'JSearch',
    employment_type: j.job_employment_type || '',
    qualifications:  (j.job_highlights?.Qualifications || []).join(' | '),
    benefits:        (j.job_highlights?.Benefits || []).join(' | ')
  }
}));

