const item = $input.first().json;
const jobData = $('Skip If Already Applied').first().json;

let scoreData = { score: 50, reason: 'AI parse error', missing_skills: [], apply: false };
try {
  const rawContent = item.choices?.[0]?.message?.content || '{}';
  const cleaned = rawContent.replace(/```json|```/g, '').trim();
  scoreData = JSON.parse(cleaned);
} catch(e) {
  scoreData.reason = 'Could not parse AI response';
}

return [{
  json: {
    ...jobData,
    ai_score:         scoreData.score || 0,
    ai_reason:        scoreData.reason || '',
    ai_missing:       (scoreData.missing_skills || []).join(', '),
    should_apply:     scoreData.apply === true && (scoreData.score || 0) >= 65
  }
}];

