const item = $input.first().json;
const jobData = $('Score >= 65?').first().json;
const config = $('⚙️ CONFIG — Edit Your Details Here').first().json;

let coverLetter = 'Cover letter generation failed.';
try {
  coverLetter = item.choices?.[0]?.message?.content?.trim() || coverLetter;
} catch(e) {}

const today = new Date().toISOString().split('T')[0];

return [{
  json: {
    ...jobData,
    cover_letter:   coverLetter,
    apply_date:     today,
    status:         'Applied',
    applied_via:    jobData.apply_link || 'Manual',
    followup_date:  new Date(Date.now() + 7*24*60*60*1000).toISOString().split('T')[0],
    user_name:      config.USER_NAME,
    user_email:     config.USER_EMAIL
  }
}];

const emails = $input.all();
const appliedJobs = $('Get All Applied Jobs').all().map(i => i.json);

if (!emails || emails.length === 0) {
  return [{ json: { has_replies: false, replies: [], applied_count: appliedJobs.length } }];
}

const recruiterEmails = emails.map(item => {
  const msg = item.json;
  const headers = msg.payload?.headers || [];
  const getHeader = (name) => headers.find(h => h.name?.toLowerCase() === name.toLowerCase())?.value || '';

  const from    = getHeader('From');
  const subject = getHeader('Subject');
  const date    = getHeader('Date');
  const bodyPart = msg.payload?.parts?.[0]?.body?.data ||
                   msg.payload?.body?.data || '';
  let body = '';
  try {
    body = Buffer.from(bodyPart, 'base64').toString('utf8').substring(0, 1500);
  } catch(e) { body = 'Could not decode body'; }

  // Try to match to an applied job
  const matched = appliedJobs.find(j =>
    subject.toLowerCase().includes(j.company?.toLowerCase()) ||
    subject.toLowerCase().includes(j.job_title?.toLowerCase()) ||
    from.toLowerCase().includes(j.company?.toLowerCase().replace(/[^a-z0-9]/g,''))
  );

  return {
    message_id:   msg.id,
    from,
    subject,
    date,
    body_snippet: body,
    matched_job:  matched ? `${matched.job_title} @ ${matched.company}` : 'Unknown',
    matched_company: matched?.company || '',
    job_id:       matched?.job_id || ''
  };
}).filter(e => e.from && e.subject);

return [{ json: {
  has_replies:   recruiterEmails.length > 0,
  replies:       recruiterEmails,
  applied_count: appliedJobs.length
}}];

const aiResult = $input.first().json;
const inboxData = $('Parse Recruiter Replies').first().json;

let aiSummary = 'No AI summary available';
try {
  aiSummary = aiResult.choices?.[0]?.message?.content?.trim() || aiSummary;
} catch(e) {}

const today = new Date().toLocaleDateString('en-US', { weekday:'long', year:'numeric', month:'long', day:'numeric' });

return [{
  json: {
    ai_summary:     aiSummary,
    reply_count:    inboxData.replies?.length || 0,
    applied_count:  inboxData.applied_count || 0,
    raw_replies:    inboxData.replies || [],
    today:          today,
    has_replies:    inboxData.has_replies || false
  }
}];
